import React, { useState, useRef, useEffect } from 'react';
// We use the Google AI SDK
import { GoogleGenerativeAI } from "@google/generative-ai";

// 🔴 ACTION: PASTE YOUR NEW KEY INSIDE THESE QUOTES
const API_KEY = "AIzaSyC35RtQVQDpvnavIumd3-Lkt0T8je5iI5w"; 

function ChatBot() {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState([
    { text: "👋 Hi! I'm CampusBot. I can help you with uploads, errors, or project ideas!", isBot: true }
  ]);
  const [input, setInput] = useState("");
  const [isThinking, setIsThinking] = useState(false);
  const messagesEndRef = useRef(null);

  // Scroll to bottom when message is sent
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, isThinking]);

  // --- THE AI BRAIN ---
  const generateResponse = async (userQuestion) => {
    try {
      // Safety Check: Did the user paste the key?
      if (!API_KEY || API_KEY.includes("AIzaSyC35RtQVQDpvnavIumd3-Lkt0T8je5iI5w")) {
        return "⚠️ Error: You forgot to paste the new API Key in the code!";
      }

      // 1. Initialize Google AI
      const genAI = new GoogleGenerativeAI(API_KEY);
      
      // 2. Select the Model (We use Flash because it is fast & free)
      const model = genAI.getGenerativeModel({ model: "gemini-1.5-flash" });

      // 3. Teach the AI about CampusCanvas
      const systemContext = `
        You are "CampusBot", the AI assistant for the CampusCanvas project.
        
        YOUR KNOWLEDGE BASE:
        - **Project Purpose:** A repository for students to archive final year projects.
        - **Tech Stack:** React.js (Frontend), Firebase (Backend), Tailwind CSS.
        - **Admin Rules:** Only Admins can "Approve" or "Reject" projects.
        - **Upload Rules:** Images must be under 1MB.
        - **Technical Detail:** We store images as Base64 strings in Firestore (No AWS S3 used).
        
        COMMON ERROR SOLUTIONS:
        - "White Screen": It's a React rendering error. Refresh the page.
        - "Slow Loading": Caused by large Base64 image strings.
        - "Deployment Failed": Check if 'eslint' warnings are blocking the build on Vercel.
        
        INSTRUCTIONS:
        - Keep answers short (under 50 words).
        - Be friendly and encouraging.
      `;

      // 4. Send Request
      const result = await model.generateContent(`${systemContext}\n\nUser Question: ${userQuestion}\nAnswer:`);
      const response = await result.response;
      return response.text();

    } catch (error) {
      console.error("AI Error:", error);
      // Detailed error message for debugging
      return `⚠️ Connection Failed: ${error.message}`;
    }
  };

  const handleSend = async () => {
    if (!input.trim()) return;

    // Add User Message
    const userMsg = { text: input, isBot: false };
    setMessages((prev) => [...prev, userMsg]);
    setInput("");
    setIsThinking(true);

    // Get AI Response
    const aiText = await generateResponse(input);

    // Add AI Message
    setIsThinking(false);
    setMessages((prev) => [...prev, { text: aiText, isBot: true }]);
  };

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end font-sans">
      
      {/* CHAT WINDOW */}
      {isOpen && (
        <div className="bg-white w-80 h-96 rounded-2xl shadow-2xl border border-gray-200 flex flex-col overflow-hidden animate-fade-in-up mb-4">
          
          {/* Header */}
          <div className="bg-indigo-600 p-4 flex justify-between items-center text-white shadow-md">
            <div className="flex items-center gap-2">
              <span className="text-xl">🤖</span>
              <div>
                <h3 className="font-bold text-sm">CampusBot</h3>
                <p className="text-[10px] text-indigo-200">AI Powered</p>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="hover:bg-indigo-700 w-8 h-8 rounded-full">✕</button>
          </div>

          {/* Messages */}
          <div className="flex-1 p-4 overflow-y-auto bg-gray-50 space-y-3">
            {messages.map((msg, index) => (
              <div key={index} className={`flex ${msg.isBot ? 'justify-start' : 'justify-end'}`}>
                <div className={`max-w-[85%] p-3 rounded-xl text-sm shadow-sm ${
                  msg.isBot 
                    ? 'bg-white border border-gray-200 text-gray-800 rounded-tl-none' 
                    : 'bg-indigo-600 text-white rounded-tr-none'
                }`}>
                  {msg.text}
                </div>
              </div>
            ))}
            {isThinking && <div className="text-xs text-gray-400 p-2">Thinking...</div>}
            <div ref={messagesEndRef} />
          </div>

          {/* Input */}
          <div className="p-3 border-t bg-white flex gap-2">
            <input 
              type="text" 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && handleSend()}
              placeholder="Ask anything..." 
              className="flex-1 bg-gray-100 rounded-full px-4 py-2 text-sm outline-none focus:ring-2 focus:ring-indigo-500 bg-gray-100"
            />
            <button onClick={handleSend} disabled={isThinking} className="bg-indigo-600 text-white w-10 h-10 rounded-full flex items-center justify-center hover:bg-indigo-700">➤</button>
          </div>
        </div>
      )}

      {/* OPEN BUTTON */}
      {!isOpen && (
        <button 
          onClick={() => setIsOpen(true)}
          className="w-16 h-16 bg-indigo-600 hover:bg-indigo-700 text-white rounded-full shadow-lg flex items-center justify-center text-3xl transition-transform hover:scale-110"
        >
          🤖
        </button>
      )}
    </div>
  );
}

export default ChatBot;
